INSERT INTO `kb_chunks` VALUES ('0db7a891-7bcb-44ed-ab0d-7b4d25ea6160:v1:0:0d676d4873fb91a0', '0db7a891-7bcb-44ed-ab0d-7b4d25ea6160', '187e1d8c-0d57-419b-b495-7560a4f184c2', 2, 0, '˿ͱ	Ѷ	ƽѶ	״	Ѷ׼	ƽ	ߵ	͵	ܹ	ƽ	Ծ·	Ծ	ԾСʱ	Ҫ	Ʒ	KMeans_Cluster	ͻֵ	DBSCAN_Cluster\n15039.0	2329.78	18.34472440944882	127	33.075313693380295	3.2426771653543307	16.95	0.12	896	7.05511811023622	12	5	5	United Kingdom	100	0	0.01828488501780127	0\n12921.0	2091.25	22.98076923076923	91	13.267445138866053	2.789230769230769	9.95	0.65	1021	11.219780219780219	11	6	8	United Kingdom	71	0	0.014466331108986256	0\n14769.0	991.27	9.011545454545454	110	9.379041850318453	2.6545454545454548	14.95	0.39	689	6.263636363636364	7	5	4	United Kingdom	107	0	0.013951935949846431	0\n16033.0	958.3	8.261206896551723	116	6.665590049249031	3.814137931034483	24.95	0.29	352	3.0344827586206895	12	5	5	United Kingdom	105	0	0.013822703029567049	0\n14796.0	884.5600000000001	6.9106250000000005	128	9.760909563755364	2.000078125	12.75	0.19	645	5.0390625	12	5	6	United Kingdom	93	0	0.0129271653089631	0\n16671.0	816.0	816.0	1		2.55	2.55	2.55	320	320.0	1	1	1	United Kingdom	1	0	0.002834572955436937	1\n16737.0	417.59999999999997	417.59999999999997	1		1.45	1.45	1.45	288	288.0	1	1	1	United Kingdom	1	0	0.0014988255313272726	1\n12798.0	244.79999999999998	244.79999999999998	1		0.85	0.85	0.85	288	288.0	1	1	1	Japan	1	0	0.0009194652027977798	1\n13099.0	207.35999999999999	207.35999999999999	1		0.72	0.72	0.72	288	288.0	1	1	1	United Kingdom	1	0	0.0007939371316163896	1', '0d676d4873fb91a0c031ec40c10dd88417b2164202ab3dadb421300f2b2c4c86', '{\"sheet\": \"source\", \"row_end\": 10, \"row_start\": 2}', 345, '2026-06-21 03:11:42');
INSERT INTO `kb_chunks` VALUES ('15209a4a-5922-49f3-b7cb-dbfb3be0cd47:v1:0:25dd88dab6418b86', '15209a4a-5922-49f3-b7cb-dbfb3be0cd47', 'a2d47e7e-87a5-432e-afd2-c6c24d8bf33e', 2, 0, '# 11\n\n**5. 文件上传 + 分析（核心差异化）**\n\n用户上传 PDF、Word、Excel，AI 直接分析。这结合你已有的 RAG 体系，是最大亮点。\n\njava\n\n```java\n// 后端接收文件，动态写入向量库\n@PostMapping(\"/upload\")\npublic Result<?> uploadDocument(@RequestParam MultipartFile file,\n                                 @RequestParam String sessionId) {\n    // 解析文件 → 切片 → 向量化 → 存入用户专属的 Redis namespace\n}\n```\n\n**6. 知识库管理页面**\n\n让用户自己上传文档建立私有知识库，这是 ChatGPT 免费版没有的功能。\n\n```\n我的知识库\n├── 公司规章制度.pdf  ✓\n├── 产品手册v2.docx  ✓\n└── 竞品分析报告.xlsx ✓\n\n[+ 上传文档]\n```\n\n**7. 提示词模板市场**\n\n预设场景模板，降低用户使用门槛：\n\n```\n📝 合同审查    🔍 竞品分析\n📊 数据解读    💡 头脑风暴\n📧 邮件撰写    🐛 代码调试\n```\n\n**8. 对话分享**\n\n生成分享链接，让用户把好的对话分享给同事，这是增长的关键。\n\n------', '25dd88dab6418b86498875c43f980420981533dbbeb9c41db0fa5fa19356733d', '{\"section\": \"11\"}', 334, '2026-06-21 03:10:15');
INSERT INTO `kb_chunks` VALUES ('15209a4a-5922-49f3-b7cb-dbfb3be0cd47:v1:1:c0b44c2f2408daaa', '15209a4a-5922-49f3-b7cb-dbfb3be0cd47', 'a2d47e7e-87a5-432e-afd2-c6c24d8bf33e', 2, 1, '### 第三阶段：商业化功能（4-6个月）\n\n**9. 积分/会员体系**\n\n```\n免费版：每天 20 次对话，不能上传文件\nPro版：无限对话 + 文件上传 + 私有知识库\n企业版：私有部署 + API 接入 + 多人协作\n```\n\n**10. 团队协作**\n\n共享知识库、共享对话、@同事，打企业内部工具市场。\n\n**11. API 开放**\n\n让开发者调用你的服务，收 Token 费用。\n\n------', 'c0b44c2f2408daaac7a82ecce11390d2402e1b7c7a2c95447ce93649836eeb47', '{\"section\": \"第三阶段：商业化功能（4-6个月）\"}', 157, '2026-06-21 03:10:15');
INSERT INTO `kb_chunks` VALUES ('15209a4a-5922-49f3-b7cb-dbfb3be0cd47:v1:2:bf7b901397ceab21', '15209a4a-5922-49f3-b7cb-dbfb3be0cd47', 'a2d47e7e-87a5-432e-afd2-c6c24d8bf33e', 2, 2, '## 四、技术优化清单\n\n**后端优化**\n\n| 问题           | 当前状况             | 优化方案                                   |\n| -------------- | -------------------- | ------------------------------------------ |\n| 流式响应编码   | 可能有乱码           | 明确设置 `text/event-stream;charset=UTF-8` |\n| 没有限流       | 单用户可打爆服务     | 加 Redis 限流，每分钟最多 20 次            |\n| 向量库每次重建 | `store()` 方法被注释 | 启动时检查是否已有数据，有则跳过           |\n| 没有异常监控   | 出错只打日志         | 接入 Sentry 或钉钉/企微告警                |\n\n**前端优化**\n\n| 问题             | 优化方案                           |\n| ---------------- | ---------------------------------- |\n| 无 Markdown 渲染 | 引入 marked + highlight.js         |\n| 打字机效果卡顿   | 当前逐字符显示性能差，改为逐词显示 |\n| 无骨架屏         | 加载时显示骨架，减少白屏感知       |\n| 不支持移动端     | 响应式布局适配，或做 PWA           |\n\n------', 'bf7b901397ceab21a8dece29586bbada035a9eb5606485076f7ec786bfc42aa1', '{\"section\": \"四、技术优化清单\"}', 394, '2026-06-21 03:10:15');
INSERT INTO `kb_chunks` VALUES ('15209a4a-5922-49f3-b7cb-dbfb3be0cd47:v1:3:837ab7d6024abe14', '15209a4a-5922-49f3-b7cb-dbfb3be0cd47', 'a2d47e7e-87a5-432e-afd2-c6c24d8bf33e', 2, 3, '## 五、最重要的一点\n\n技术只是门槛，**真正留住用户靠的是垂直场景的数据积累**。\n\n你喂进 RAG 的专业文档质量，决定了你的产品天花板。ChatGPT 的通用性是它的优势，也是它的弱点——它不会比一个喂了 10000 份行业合同的法律 AI 更懂法律。\n\n**建议的最小闭环路径：**\n\n选一个垂直领域 → 收集该领域高质量文档 → 喂入知识库 → 做好 Markdown 渲染和对话历史 → 找 20 个目标用户内测 → 根据反馈迭代\n\n这条路走通了，比做一个功能和 ChatGPT 一模一样但质量差一半的通用产品，更有商业价值。', '837ab7d6024abe1486ff93369dd595ce80d6aebf8fbeedc1bfc502f2787443fb', '{\"section\": \"五、最重要的一点\"}', 209, '2026-06-21 03:10:15');
INSERT INTO `kb_chunks` VALUES ('16336868-3c7b-4c5f-a28a-8c463190bb75:v1:0:5a87252533d8a1dd', '16336868-3c7b-4c5f-a28a-8c463190bb75', 'ecd72e4c-2af0-4bd7-920d-e9dac913fb3e', 14, 0, 'BU39H-WRAM0-ITY3R-KI9FV-HNE0J-RXA64\n\ngithub上传全流程\necho \"# ros_ai\" >> README.md\ngit init\ngit add .\ngit commit -m \"first commit\"\ngit branch -M main\n git remote add origin https://github.com/Kb-LLL/ros_ai.git\ngit push -u origin main', '5a87252533d8a1dddf0578def05c5e64f7850f8f633b401fef7305d64fcb7ef5', '{\"section\": null}', 70, '2026-06-21 04:59:32');
