INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:1:44f125a26fea7ad3', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 1, '## SQL介绍\n\n![](E:\\人工智能\\Snipaste_2026-04-09_21-26-22.png)', '44f125a26fea7ad38315f9f43912576a732294f4cc8619c7e530d49f91fad47b', '{\"section\": \"SQL介绍\"}', 29, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:10:b4841867f7e8a9e4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 10, '## Anaconda\n\n![](E:\\人工智能\\Snipaste_2026-04-13_23-20-45.png)\n\nanaconda包管理功能-可以通过命令安装\n\n![](E:\\人工智能\\Snipaste_2026-04-14_10-05-06.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-14_11-20-10.png)', 'b4841867f7e8a9e451f7f0ef7e71995fc3dcac09b933d0ae86dabda32928b826', '{\"section\": \"Anaconda\"}', 90, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:100:3ab53b3a73a9a1cc', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 100, '#### cart数  (又把他分为分类回归决策树)\n\nClassification and Regression Tree\n\n**基尼指数**:各个分类占比*基尼值累加起来就是基尼指数\n\ncart模型是一种决策树模型,它既可以用于分类,也可以用于回归\n\ncart回归树使用**平方误差最小化**策略\n\ncart分类生成树采用的**基尼指数最小化**策略\n\n基尼值越小越好,越小说明数据越集中,越大说明数据越混乱\n\n![](E:\\人工智能\\Snipaste_2026-06-10_23-54-22.png)\n\n基尼值全是套用公式来算\n$$\n1-1^2就是1-10/10\n$$\n10/10就是全是红色的类,抽哪个都是红色的\n$$\n1-0.5^2-0.5^2就是1-5/10-5/10\n$$\n5/10就是5个红色的类和5个蓝色的类,累加起来\n\n后面有其他的类一样算平方和累加\n\n![](E:\\人工智能\\Snipaste_2026-06-11_23-33-37.png)\n\n4.计算年收入特征列的基尼值指数\n\n![](E:\\人工智能\\Snipaste_2026-06-12_00-13-39.png)\n\n![](E:\\人工智能\\Snipaste_2026-06-12_00-23-15.png)\n\ncart树的决策树的作用?\n\n分类和回归\n\n基尼指数的作用?\n\n特征筛选，基尼指数值越小，则说明优先选择该特征\n\n基尼指数是cart算法中用于划分属性的重要依据\n\n三种分类树的对比\n\n![](E:\\人工智能\\Snipaste_2026-06-13_13-10-58.png)', '3ab53b3a73a9a1cc3ea9d08d0463811fde55959dea95010d4f134c0f9f6da053', '{\"section\": \"cart数  (又把他分为分类回归决策树)\"}', 472, '2026-06-21 04:59:06');
