INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:18:2345bfde96bf137d', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 18, '# 例如: Python: str -> Pandas: object,  Python: None -> Pandas: nan,NAN,NaN,', '2345bfde96bf137d9e4ea7e804609c64151871896dfc7975fe98ac5c4c13eeb6', '{\"section\": \"例如: Python: str -> Pandas: object,  Python: None -> Pandas: nan,NAN,NaN,\"}', 26, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:19:3cbb71c800094d72', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 19, '# Pandas还支持category分类类型, 针对于分类数据操作更快, 更节省内存.\n```\n\n**把数据里的空值（缺失值），用【该列的平均值】填充进去**\n\n让数据变完整，方便后续计算、画图、建模。\n\n------', '3cbb71c800094d723bbc20994927f48c663eb61dcc4e7e05baf3d09af3de7835', '{\"section\": \"Pandas还支持category分类类型, 针对于分类数据操作更快, 更节省内存.\"}', 88, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:2:f8b8d40ca46bce67', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 2, '## DDL,操作数据库,数据库,数据表,字段\n\n![](E:\\人工智能\\Snipaste_2026-04-09_22-01-06.png)\n\n实际开发数据库得预留2-7个字段\n\n![](E:\\人工智能\\Snipaste_2026-04-09_23-28-54.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-11_13-36-11.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-11_13-40-36.png)', 'f8b8d40ca46bce675c87e05edab3bd3419f8349944533ec507b767bc139973f5', '{\"section\": \"DDL,操作数据库,数据库,数据表,字段\"}', 132, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:20:8a39b7d85326671e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 20, '# 填充缺失值.\n\n```', '8a39b7d85326671e31ee288b0795dbad09f8a22501354bbc88b903d48de14be9', '{\"section\": \"填充缺失值.\"}', 10, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:21:7e69af65749cb44a', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 21, '# 写法2: 填充 每列的平均值.\n```\n\n用**平均值填充空值**。\n\n```\nmovie_df[\'Revenue (Millions)\'].fillna(\n    movie_df[\'Revenue (Millions)\'].mean(),\n    inplace=True\n)\n```', '7e69af65749cb44add93eb12b00f6ddb14b0aa2c8379501b600d1fbc23b049ea', '{\"section\": \"写法2: 填充 每列的平均值.\"}', 66, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:22:93763bd80d1da962', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 22, '### 意思：\n\n1. ```\n   movie_df[\'Revenue (Millions)\']\n   ```\n\n   → 选中 票房收入（百万）这一列\n\n2. ```\n   .fillna(...)\n   ```\n\n   → 填充这一列里的 空值（NaN）\n\n3. ```\n   movie_df[\'Revenue (Millions)\'].mean()\n   ```\n\n   → 用 这一列自己的平均值去填充空值\n\n4. ```\n   inplace=True\n   ```\n\n   → 直接修改原数据，不用重新赋值', '93763bd80d1da962e90c9504347f27009c24864c4bfd17444bda74a4310d9d50', '{\"section\": \"意思：\"}', 128, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:23:84674e2766ba5082', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 23, '# 机器学习', '84674e2766ba5082ea42f5d432001ab1cc3c4721fe7e771d0c54d183e1efac8d', '{\"section\": \"机器学习\"}', 5, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:24:424359e53e16a6b8', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 24, '## 基础名词概念\n\n什么叫样本,一条数据叫样本\n\n什么叫特征,我分析的字段就叫特征\n\n什么叫标签,我要的结果字段就叫标签\n\n什么训练集,给模型训练的时候用的\n\n什么叫测试集,测试结果用的\n\n训练集和测试集占比  7:3 或者 8:2      一般7:3比较多\n\n![](E:\\人工智能\\Snipaste_2026-04-18_21-47-20.png)\n\n有监督学习:有特征有标签\n\n无监督学习:有特征无标签\n\n半监督学习:部分内容打标记,让程序进行打过标记来进行训练\n部分有标签,部分没有标签\n\n建模流程\n\n![](E:\\人工智能\\Snipaste_2026-04-18_22-04-35.png)\n\nai:用计算机模拟人脑,让计算机能够像人类一样理性的思考,行动\n\n机器学习:先训练再预测\n\n机器学习(Machine Learning)(ML):机器自动学习,不是人为规则编程\n\n深度学习(Deep Learning)(DL):大脑仿生,设计一层一层的神经元模拟万事万物\n\n![](E:\\人工智能\\Snipaste_2026-04-19_20-18-00.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-19_20-46-13.png)\n\nAI、ML、DL三者之间的关系\n\n机器学习是实现人工智能的一种途径\n\n深度学习是机器学习的一种方法发展而来的\n\n算法的学习方式有2种\n\n基于规则的学习\n\n基于模型的学习\n\nAIGC:就是用ai生成各种内容\n\nG是生成的意思\n\nC是内容的意思\n\n![](E:\\人工智能\\Snipaste_2026-04-28_17-26-18.png)', '424359e53e16a6b826cf3d5dd6e475dc8bfcbc5d5d5247bcb23b93868e230681', '{\"section\": \"基础名词概念\"}', 494, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:25:ce50137b265de7e7', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 25, '## 有监督学习\n\n有监督学习:有特征有标签\n\n![](E:\\人工智能\\Snipaste_2026-04-20_00-04-35.png)\n\n直接算**欧式距离:**对应维度的**差值**然后各平方和相加,相加完开平方\n\n39-23=16\n\n0-3=3\n\n31-17=14\n\n(16²+3²+14²)的开平方根=21.4709\n\nKNN：k近邻K个临近的领居\n\nk值过小过拟合,k值过大欠拟合\n\nk值过小容易受到异常点的影响，会过度分析样本特征,所以导致可能会学到一些脏的标签,所以容易发生过拟合\n\nk值过大例如值等于n,模型就变得简单了,因为投票结果永远都是类别最多的那一个,所以欠拟合\n\n![](E:\\人工智能\\Snipaste_2026-04-21_11-36-20.png)\n\n例如:上面5个都靠近最底那个,但是爱情片最多靠近最下面那个,所以最终这个类型是爱情片', 'ce50137b265de7e76355a4c5447286025327bd8dc47f39673f79de741b3868e6', '{\"section\": \"有监督学习\"}', 302, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:26:1948f31e34d69e64', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 26, '## 无监督学习\n\n无监督学习:有特征无标签\n\n![](E:\\人工智能\\Snipaste_2026-04-21_11-43-52.png)\n\n无监督学习:无标签,这种叫聚类\n\n![](E:\\人工智能\\Snipaste_2026-04-21_11-48-46.png)', '1948f31e34d69e64e5177a2006cde8144a47f8a0abd2d0087994dc62cd5d0b74', '{\"section\": \"无监督学习\"}', 82, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:27:fc0a298c1243bd54', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 27, '## 半监督学习\n\n半监督学习：部分有标签,部分没有标签\n\n![](E:\\人工智能\\Snipaste_2026-04-21_12-00-46.png)\n\n肺部ct中的数据先有专家判断有没有问题,专家做完判断然后做标签,做完标签然后拿去训练模型,剩下的数据没有标签的就拿这个模型去预测\n\n**降低标记数据成本**', 'fc0a298c1243bd54c5e27a862e1155657ff9e6dd28eecd2b3eeec484ca961aff', '{\"section\": \"半监督学习\"}', 124, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:28:86c31fc458ab57cb', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 28, '## 强化学习\n\n![](E:\\人工智能\\Snipaste_2026-04-21_12-14-31.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-21_12-21-25.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-21_12-23-08.png)', '86c31fc458ab57cb2e04234e73bcbc6aacd569c0c8b7027af2af485318adedce', '{\"section\": \"强化学习\"}', 78, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:29:4dbe89eadedcab86', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 29, '## 机器学习建模流程\n\n第一步:加载数据\n\n第二步:数据预处理\n\n第三步:特征工程\n\n第四步:训练模型\n\n第五步:模型评估\n\n第六步:模型预测\n\n![](E:\\人工智能\\Snipaste_2026-04-21_22-11-50.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-21_22-39-10.png)', '4dbe89eadedcab86831e0786128b84181c659371efea3820786d6403dc4cbce2', '{\"section\": \"机器学习建模流程\"}', 107, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:3:8dada2668efdc919', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 3, '## 单表查询\n\n![](E:\\人工智能\\Snipaste_2026-04-12_10-33-50.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_10-52-02.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_10-56-47.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-36-41.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-36-54.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-37-20.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-37-31.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-41-17.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_12-51-43.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-13-29.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-18-19.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-24-04.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-30-15.png)', '8dada2668efdc9190991327e5209f0e8310e1431cfcfd59d138a3ba605a8cbaf', '{\"section\": \"单表查询\"}', 318, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:30:6c468a204a70f02b', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 30, '## 特征工程介绍\n\n特征工程:利用专用背景知识和技巧**处理数据**,让机器学习算法效果最好\n\n数据和特征定了机器学习的上限,而模型和算法只是逼近这个上限而已\n\n![](E:\\人工智能\\Snipaste_2026-04-21_22-40-38.png)\n\n特征(Feature):对**任务有用**的属性信息', '6c468a204a70f02b398c8b33241c4bd3f0541bc5e06daf56c0eaebaf5e0dfc2d', '{\"section\": \"特征工程介绍\"}', 119, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:31:9127b80857aea9f4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 31, '### 1.特征提取(会改变数据)\n\n从原始数据中提取与任务相关的特征\n\n![](E:\\人工智能\\Snipaste_2026-04-21_23-44-28.png)\n\n其实也可以让ai代入生物专家角色,叫Ai提取特征', '9127b80857aea9f4a0a5f9cf75a0883f15e61b8f671c36fdf788f5f9357b6726', '{\"section\": \"1.特征提取(会改变数据)\"}', 78, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:32:01c5a2362bf72e82', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 32, '### 2.特征预处理\n\n特征对模型产生影响;**因量纲问题**,有些特征对模型影响大、有些影响小(导致鲁棒性不稳定)\n\n**鲁棒性（Robustness）= 模型的稳定性、抗干扰能力**\n\n大白话解释：\n\n数据集出现**轻微噪声、异常值、数据波动、数据范围变化、少量脏数据**时，\n\n模型的预测效果**不会大幅度变差、结果不会跑偏、训练不会崩溃**，就叫**鲁棒性好**。\n\n反之：\n\n数据稍微有点异常、稍微波动一点，模型精度暴跌、训练震荡不收敛、预测结果严重失真，就是**鲁棒性差**。\n\n简单对比：\n\n- 鲁棒性好：风吹雨打都稳定\n- 鲁棒性差：一点小干扰就直接垮掉', '01c5a2362bf72e821e6b2e55a389d0588e5b8f96f584896093234254a3706992', '{\"section\": \"2.特征预处理\"}', 254, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:33:81c52e7062c6d612', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 33, '#### 量纲问题\n\n单位问题\n\n简单说：**特征的单位、数值大小级别、取值范围**。\n\n每个特征自带的**数字量级大小**，就是量纲。\n\n比如你数据集里的特征：\n\n- 年龄：`0 ~ 100`\n- 身高：`100 ~ 200 cm`\n- 月收入：`1000 ~ 100000 元`\n\n这三个特征，数字大小天差地别，**量级不一样**，就是量纲不同。\n\n![](E:\\人工智能\\Snipaste_2026-04-21_23-55-36.png)\n\n上面的计算公式是归一化操作', '81c52e7062c6d612acf805400c6beee382fedd0f2cb1d591c1a4f48c0cedff4f', '{\"section\": \"量纲问题\"}', 171, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:34:a86538f82518bbb4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 34, '### 3.特征降维(会修改原始数据)\n\n特征降维:将原始数据的维度降低,叫做特征降维    3d降2d', 'a86538f82518bbb4e0ae45890d19028a0f87ff4444018182a603923a11844a1d', '{\"section\": \"3.特征降维(会修改原始数据)\"}', 43, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:35:cf84c06eefee798e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 35, '### 4.特征选择(对原始数据不会有影响)\n\n特征选择:原始数据特征很多,但是对模型训练相关是其中一个特征集合子集\n\n简单的说:就是我原来有10列数据,然后只用其中的3列数据', 'cf84c06eefee798e82e452f581196c6539e14d526f84a8e5e0dbdf81c650d149', '{\"section\": \"4.特征选择(对原始数据不会有影响)\"}', 82, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:36:ba5172455a033402', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 36, '### 5.特征组合\n\n把多个的特征合并成一个特征。一般利用乘法或加法来完成\n\n![](E:\\人工智能\\Snipaste_2026-04-21_23-57-37.png)', 'ba5172455a033402d1a16abf9e9cde41a844a39c56ac76408506f55b94e2bfc8', '{\"section\": \"5.特征组合\"}', 59, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:37:44f2d5aac07a1860', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 37, '## 拟合问题\n\n用在机器学习领域,用来表示模型对样本点的拟合情况', '44f2d5aac07a1860bd17aea36458e183879adb078cfc4a061eca57e7bdc6ad79', '{\"section\": \"拟合问题\"}', 30, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:38:d4f63b2b8f14de06', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 38, '### 拟合(fitting)\n\n拟合:模型在训练集上表现很好、在测试集表现也很好', 'd4f63b2b8f14de060cc4c1565af368cd9d2038f4cab28901e69b674df7c4e819', '{\"section\": \"拟合(fitting)\"}', 32, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:39:e7bcedea4503eae6', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 39, '### 欠拟合(under-fitting)\n\n欠拟合:模型在训练集上表现很差、在测试集表现也很差\n\n产生原因:模型过于简单\n\n![](E:\\人工智能\\Snipaste_2026-04-22_00-20-03.png)\n\n解决方法:欠拟合可以通过增加特征来解决', 'e7bcedea4503eae644286da350a5b63ddd2458d0feaf224dfb44641721f6564e', '{\"section\": \"欠拟合(under-fitting)\"}', 90, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:4:4f49b672976b3dfb', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 4, '### 页数,单页查询\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-36-40.png)', '4f49b672976b3dfb3889bd3af03941cd9f16846795ea81ad1ee33c07ff6d3795', '{\"section\": \"页数,单页查询\"}', 34, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:40:e69874ed7528740e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 40, '### 过拟合(over-fitting)\n\n过拟合:模型在训练集上表现很好、在测试集表现也很差\n\n产生原因:模型太过于复杂、数据不纯、训练数据太少\n\n![](E:\\人工智能\\Snipaste_2026-04-22_00-22-10.png)\n\n解决方法:过拟合可以通过正则化、异常值检测、特征降维等方法来解决\n\n正则化:\n\n​	L1正则化\n\n​	L2正则化', 'e69874ed7528740e6ff9d2c3c2bb11e4b0c978c1f13e222781f7934af2a74205', '{\"section\": \"过拟合(over-fitting)\"}', 130, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:41:6767f3c863bc594c', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 41, '### 泛化Generalization\n\n**模型拟合情况=泛化能力**\n\n泛化:模型在新数据集(非训练数据)上的表现好坏的能力\n\n简单的说:\n\n模型A：在测试集正确率表现是95%\n\n模型B：在测试集正确率表现是95%', '6767f3c863bc594c1e3d8222cb768bd932b94a788aaad0ee972aaf0a2e0f4c9f', '{\"section\": \"泛化Generalization\"}', 84, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:42:a48429cf8be133a4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 42, '### 奥卡姆剃刀原则\n\n奥卡姆剃刀原则：给定两个具有相同**相同泛化误差**的模型,**较简单的模型**比较复杂的模型更可取\n\n例子: 用了网格搜索+交叉验证\n\n![](E:\\人工智能\\Snipaste_2026-04-29_12-28-42.png)\n\n相同泛化误差：就是多个模型在测试集正确率表现差不多相同,哪个更简单的就用哪个', 'a48429cf8be133a4fe86082f994d32fe493b650e0ae964ca938ba566de1197af', '{\"section\": \"奥卡姆剃刀原则\"}', 136, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:43:c5cbb448aac5e95c', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 43, '## scikit-learn库\n\n<img src=\"E:\\人工智能\\Snipaste_2026-04-22_11-35-46.png\" style=\"zoom:50%;\" />\n\n​', 'c5cbb448aac5e95c481fc1e22213d3b568407bf5a44509f1ca9332d8c1dbf348', '{\"section\": \"scikit-learn库\"}', 43, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:44:582f6766992ae4f8', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 44, '### scikit-learn算法选择路径图\n\n![](E:\\人工智能\\Snipaste_2026-04-22_11-47-03.png)', '582f6766992ae4f8a4f009a9fa388a6a4f457c09300b803dfbb7e6121bf36e11', '{\"section\": \"scikit-learn算法选择路径图\"}', 37, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:45:144ce0fc3dac00bf', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 45, '## knn算法(懒惰学习（Lazy Learning）)\n\n![](E:\\人工智能\\Snipaste_2026-04-22_21-14-02.png)\n\n举个真实例子\n判断电影类型\n已有用户数据：\n年龄\n喜欢动作片\n类型\n18\n高\n热血用户\n20\n高\n热血用户\n45\n低\n文艺用户\n现在一个：\n19岁\n喜欢动作片\nKNN 会发现：\n它离前两个用户更近。\n因此：\n→ 判定为“热血用户”。\n\n若k值与训练集样本数相同,会导致最终模型的结果都是指向训练集中类别数最多的那一类,忽略了数据当中其它的重要信息,模型会过于简单\n\n实际工作中经常使用交叉验证的方式去选取最优的k值,而且一般情况下，k值都是比较小的数值\n\n![](E:\\人工智能\\Snipaste_2026-04-23_20-41-06.png)', '144ce0fc3dac00bfd89ae3abe5952e24c2ee6b9d277547ca2e47b43e1aa9ab8e', '{\"section\": \"knn算法(懒惰学习（Lazy Learning）)\"}', 256, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:46:12072600c90afc6e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 46, '### 曼哈顿距离\n\n![](E:\\人工智能\\Snipaste_2026-04-23_23-17-37.png)\n\n点(0,0)   和   点(6,6)\n\n最短路径无论怎么走都是12步 (用曼哈顿距离算)', '12072600c90afc6e87e265004ff4b55d65c4d76586b25df91286fb94792264f6', '{\"section\": \"曼哈顿距离\"}', 67, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:47:382fe6106bf38511', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 47, '### 切比雪夫距离\n\n![](E:\\人工智能\\Snipaste_2026-04-23_23-27-16.png)\n\n这个切比雪夫距离可以斜着走\n\n维度值直接绝对值在比较选大的那个就是最短距离', '382fe6106bf385111023af0fbcb456b78987daac7cdfeae5bef5d6be8f87cd34', '{\"section\": \"切比雪夫距离\"}', 68, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:48:8de2e26f9170df4c', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 48, '### 闵可夫斯基距离\n\n![](E:\\人工智能\\Snipaste_2026-04-23_23-33-24.png)', '8de2e26f9170df4cf7be5a71368a9dbd66dd8540db69bd96fadce6194fbabaaa', '{\"section\": \"闵可夫斯基距离\"}', 34, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:49:76d69f7b2a81de65', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 49, '## 特征预处理', '76d69f7b2a81de6568a923624ab5d491397cd5f93db03f0503183ef996032827', '{\"section\": \"特征预处理\"}', 7, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:5:2667b76d6356492e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 5, '## sql执行顺序\n\n![](E:\\人工智能\\Snipaste_2026-04-12_13-39-44.png)\n\n一对多\n\n![](E:\\人工智能\\Snipaste_2026-04-12_23-38-18.png)\n\n多对多建表\n\n![](E:\\人工智能\\Snipaste_2026-04-12_23-49-53.png)\n\n一对一建表\n\n![](E:\\人工智能\\Snipaste_2026-04-12_23-52-10.png)\n\n删除外键约束和添加外键约束\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-20-38.png)\n\n内连接\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-28-51.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-40-11.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-32-01.png)\n\n左连接\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-29-09.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-43-11.png)\n\n右连接\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-29-26.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-43-25.png)\n\n全连接\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-29-43.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-43-44.png)\n\n左外连接和右外连接和全连接语法语句\n\n![](E:\\人工智能\\Snipaste_2026-04-13_00-53-44.png)\n\n子查询\n\n![](E:\\人工智能\\Snipaste_2026-04-13_01-01-29.png)\n\ncase when语法\n![](E:\\人工智能\\Snipaste_2026-04-13_01-06-47.png)', '2667b76d6356492e05e0cc0638ee26953587c94968c1a5349a5b874c622f355b', '{\"section\": \"sql执行顺序\"}', 477, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:50:44a5967d5521e56b', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 50, '### 归一化(适合小数据集)\n\n弊端:容易受到最大值和最小值影响\n\n![](E:\\人工智能\\Snipaste_2026-04-23_23-50-30.png)\n\nmx最大值\n\nmi最小值\n\npreprocessing:预处理\n\nMinMaxScaler:归一化对象\n\n<img src=\"E:\\人工智能\\Snipaste_2026-04-23_23-56-37.png\" style=\"zoom:67%;\" />', '44a5967d5521e56b103c67900171ad1159b4c6a67170929282e39d515b78277b', '{\"section\": \"归一化(适合小数据集)\"}', 110, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:51:c3277f3b038b1393', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 51, '### 标准化(适用于大数据集的处理)\n\n结论:无论是归一化,还是标准化,目的都是为了解决因为量纲问题,导致模型评估较低等问题\n\n![](E:\\人工智能\\Snipaste_2026-04-24_12-50-48.png)\n\n方差计算公式:该列每个值和该列均值的差的平方和求平均值\n\n标准差计算公式:方差开平方根\n\n按照上面数据求\n\n`x_train` 有 3 个样本，4 个特征：\n\n| 特征 | 原始值       | 均值                      | 方差 (`var_`) 计算过程                                       | 结果       | 标准差 (`scale_`)    |\n| :--- | :----------- | :------------------------ | :----------------------------------------------------------- | :--------- | :------------------- |\n| 1    | [90, 60, 75] | (90+60+75)/3 = **75**     | ((90-75)²+(60-75)²+(75-75)²) / 3 = (225+225+0) / 3           | **150.0**  | √150 ≈ **12.247**    |\n| 2    | [2, 4, 3]    | (2+4+3)/3 = **3**         | ((2-3)²+(4-3)²+(3-3)²) / 3 = (1+1+0) / 3                     | **0.6667** | √0.6667 ≈ **0.8165** |\n| 3    | [10, 15, 13] | (10+15+13', 'c3277f3b038b13931cded3cfbc48b84e03c908022eac91f3d6bb7fdb7b887794', '{\"section\": \"标准化(适用于大数据集的处理)\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:52:56a0999b6b3f0157', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 52, '= **3**         | ((2-3)²+(4-3)²+(3-3)²) / 3 = (1+1+0) / 3                     | **0.6667** | √0.6667 ≈ **0.8165** |\n| 3    | [10, 15, 13] | (10+15+13)/3 ≈ **12.667** | ((10-12.667)²+(15-12.667)²+(13-12.667)²) / 3 ≈ (7.111+5.444+0.111) / 3 ≈ 12.666 / 3 | **4.222**  | √4.222 ≈ **2.055**   |\n| 4    | [40, 45, 46] | (40+45+46)/3 ≈ **43.667** | ((40-43.667)²+(45-43.667)²+(46-43.667)²) / 3 ≈ (13.444+1.778+5.444) / 3 ≈ 20.666 / 3 | **6.889**  | √6.889 ≈ **2.625**   |\n\n![](E:\\人工智能\\Snipaste_2026-04-24_14-00-13.png)\n\n大胆的推测,细心的求证s', '56a0999b6b3f0157a97d49401bbb42c2a7a1af48e62bb956d3d30cea0f40312e', '{\"section\": \"标准化(适用于大数据集的处理)\"}', 305, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:53:b4bde33d0b864eb0', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 53, '## 切分训练集的时候\n\n```python\n#2.数据的预处理\nX_train,X_test,y_train,y_test = train_test_split(iris_data.data,iris_data.target,test_size=0.2,random_state=22)\n```\n\n有了这个random_state=22\n\n![](E:\\人工智能\\Snipaste_2026-04-27_18-05-57.png)\n\n![](E:\\人工智能\\Snipaste_2026-04-27_18-06-02.png)\n\n再次运行还是这样,8:2的比例训练集顺序都一样\n\n下面这个是没加random_state=？？？(???是个随机数来的.随便填)\n\n```\nX_train,X_test,y_train,y_test = train_test_split(iris_data.data,iris_data.target,test_size=0.2)\n```\n\n![](E:\\人工智能\\Snipaste_2026-04-27_18-11-37.png)\n\n很明显2此切分的都不一样', 'b4bde33d0b864eb0f2dc43fdfb6ae9dc699b334237adfda70ce483456de61ca0', '{\"section\": \"切分训练集的时候\"}', 226, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:54:824683fcab004087', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 54, '### fit_transform和transform区别\n\n#3.2对特征列进行标准化, 即:x_train:训练集的特征数据,x_test:测试集的特征数据\n\nfit_transform:兼具fit和transform的功能,即:训练,转换.该函数适用于:第一次进行标准化的时候使用。**一般用于处理:训练集**\n\nx_train = transfer.fit_transform(X_train)\n#transform:只有转换,该函数适用于:重复进行标准化动作时使用,**一般用于对测试集进行标准化**\nx_test = transfer.transform(X_test)\n\n```\n#3.特征工程(提取,预处理...)\n#思考1:特征提取:因为数据只有4个特征列(量纲问题没怎么出现,单位值相差不大),切都是我们用的,所有这里无需做特征提取\n#思考2:特征预处理:因为数据源的4列特征差值不大\n#3.1创建标准化对象\ntransfer = StandardScaler()\n#3.2对特征列进行标准化, 即:x_train:训练集的特征数据,x_test:测试集的特征数据\nx_train = transfer.fit_transform(X_train)\n#transform:只有转换,该函数适用于:重复进行标准化动作时使用,一般用于对测试集进行标准化\nx_test = transfer.transform(X_test)\n```', '824683fcab00408752b632936c83f3d08d0ab3ff235c30c5c10b6e3dc19973b5', '{\"section\": \"fit_transform和transform区别\"}', 379, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:55:2420f2c5827d3636', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 55, '### 交叉验证\n\n![](E:\\人工智能\\Snipaste_2026-04-28_22-21-20.png)', '2420f2c5827d363696d8f847ea722d05d048812becb8d348dffdbce4b42186d6', '{\"section\": \"交叉验证\"}', 31, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:56:09a9838d70b16873', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 56, '### 网格搜索\n\n![](E:\\人工智能\\Snipaste_2026-04-29_00-22-46.png)\n\n交叉验证网格搜索   api和应用举例\n\n![](E:\\人工智能\\Snipaste_2026-04-29_00-28-56.png)\n\n<img src=\"E:\\人工智能\\Snipaste_2026-04-29_00-37-22.png\" style=\"zoom:67%;\" />\n\n​				超参数:\n\n​						需要用户手动录入的数据,不同的超参(组合),可能会影响模型的最终评测结果\n\n大白话解释:网格搜索 + 交叉验证, 本质上指的是 GridSearchCV这个api,它会帮我们寻找最优参数(供参考)\n\n交叉验证和网格搜索的目的是什么？\n\n1.为了让评估的模型更加准确可信,一般会使用交叉验证网格搜索去完成任务\n\n2.有些算法模型本身自带较多的超参数,无法高效的去筛选比较合适的超参函数组合\n\n3.使用交叉验证和网格搜索可以提升模型的可信度和查找最佳参数组合的效率', '09a9838d70b1687333ac24b5663c60fb5e3ee28aa2ef17954ec0725f692f9029', '{\"section\": \"网格搜索\"}', 314, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:57:7994d394edd0ff85', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 57, '## 线性回归\n\n线性回归API\n\n线性回归又分成**一元线性回归**和**多元线性回归**\n\n  **一元线性回归:**\n\n特点:1个特征列,1个标签列\n\n例如:基于 身高预测 体重\n\n**多元线性回归:**\n\n特点:多个特征列,1个标签列\n\n例如:基于 学历, 考试成绩, 专业,工作年限 -> 预测你的薪资\n\n**损失函数**:用来描述预测值和真实值的差值   就是让其**误差**最小\n\n**误差=预测值—真实值**\n\n误差又由**正规方程法**和**梯度下降法**来控制\n\n梯度下降很重要\n\n回归模型评估方法: MAE、MSE、RMSE\n\nMAE：Mean Absolute Error:平均绝对误差\n\nMSE：Mean Square Error:均方误差\n\nRMSE：Root Mean Square Error:均方根误差\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-06_11-44-03.png\" style=\"zoom:80%;\" />', '7994d394edd0ff858f2d478d3d98b21f9b25301bed9384b27a1b14f0b16f80d2', '{\"section\": \"线性回归\"}', 294, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:58:c42762e203c77ce9', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 58, '### 线性回归概念\n\n![](E:\\人工智能\\Snipaste_2026-05-07_21-49-56.png)\n$$\nW^T         这个符号符号就是w的转置\n$$', 'c42762e203c77ce9f8d3f0cbdc521c9a93a2f06e78454e96c3248cf600c7e94a', '{\"section\": \"线性回归概念\"}', 52, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:59:50fd1dc19a8a6006', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 59, '### 线性回归概念\n\n![](E:\\人工智能\\Snipaste_2026-05-07_22-19-00.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-08_10-51-07.png)\n\n损失函数:衡量每个样本预测值和真实值效果的函数,也叫代价函数、成本函数、目标函数\n\n如何让损失函数最小？\n\n答案:\n\n- [ ] 思路1:正规方程法\n\n- [ ] 思路2:梯度下降法\n\n  流程:\n\n  ​		1.给定初始位置,步长(学习率)\n\n  ​		这个学习率必须设置在0.01 ~ 0.0001  之间\n\n  ​		学习率过大会导致梯度震荡或梯度爆炸容易错过最低的那个点\n\n  ​		学习率过小那么迭代次数就会过多\n\n  ​		2.计算该点当前的梯度的**负方向**\n\n  ​		3.向该负梯度方向移动步长\n\n  ​		4.重复第2~3步骤,直接结束\n\n  梯度下降什么时候结束呢?\n\n  1.当梯度值达到合理范围(例如:0.03~0.05)\n\n  2.设置固定的步数(例如:循环10次停止这样)\n\n$$\nl^`(x)这个就是损失函数的写法\n$$\n\n![](E:\\人工智能\\Snipaste_2026-05-08_11-54-41.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-08_11-55-59.png)', '50fd1dc19a8a600632a6af8c9bf85f74a99622dfe1d8688a20bb84270ba123ad', '{\"section\": \"线性回归概念\"}', 395, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:6:2fd60fef3c87d213', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 6, '## numpy\n\n![](E:\\人工智能\\Snipaste_2026-04-13_22-53-32.png)', '2fd60fef3c87d2135179c96756edf5e60eae6f6dadea04349f9d7dbbd5802398', '{\"section\": \"numpy\"}', 27, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:60:e9159b199c34ccf5', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 60, '#### 损失函数的分类:\n\n最小二乘：每个样本点误差的平方和\n\n均方误差(MSE):每个样本点误差的平方和  /  样本个数\n\n均方根误差(RMSE):均方误差 开平方根\n\n平均绝对误差(MAE)：每个样本点误差的绝对值和 / 样本个数\n\n损失函数是描述你的算法行还是不行的', 'e9159b199c34ccf5e9bafdf8c3d19cb8f0009918260c8f37de6c983f4d2a31da', '{\"section\": \"损失函数的分类:\"}', 113, '2026-06-21 04:59:06');
