INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:64:ca61d0d865b9b44c', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 64, '####  矩阵运算\n\n ![](E:\\人工智能\\Snipaste_2026-05-10_09-58-15.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-10_10-05-01.png)\n\nN就是代表行,D代表列\n\n![](E:\\人工智能\\Snipaste_2026-05-10_10-19-24.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-10_10-26-51.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-10_10-28-48.png)\n\n逆矩阵运算\n\n![](E:\\人工智能\\Snipaste_2026-05-10_10-44-07.png)\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-10_10-45-01.png\" style=\"zoom:50%;\" />', 'ca61d0d865b9b44cd93d187446f6b409ca0ad140254ebd1f7b46dec6b5818ec0', '{\"section\": \"矩阵运算\"}', 204, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:65:8fe2dbd19e39d1f4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 65, '### 一元回归正规方程法\n\n![](E:\\人工智能\\Snipaste_2026-05-10_11-24-56.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-10_11-25-45.png)\n$$\n一元线性方程 J(k,b) = \\sum_{i=1}^{m}(kx^{(i)}+b-y^{(i)})^2\n$$\n多元线性回归- 正规方程法\n\n![](E:\\人工智能\\Snipaste_2026-05-10_22-31-12.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-10_23-06-45.png)\n$$\n||Xw - y ||_{2}^2\n$$\n这里的X   以及w 如下			(这里的1行数据在python里的pandas里的Series是一列数据并不是行,而X在pandas里的dataFrame是多行数据)\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-11_10-51-22.png\" style=\"zoom:50%;\" />\n\n多元线性回归-正规方程法\n\n![](E:\\人工智能\\Snipaste_2026-05-10_23-58-25.png)\n$$\n正规方程的\n\nw = (X^TX)^{-1}X^Ty\n$$', '8fe2dbd19e39d1f4b1e53dce233d4ae951c17ecdfd14bed33db5ff8a645bbf93', '{\"section\": \"一元回归正规方程法\"}', 330, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:66:cfff7f98a1bcab15', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 66, '## 梯度下降法\n\n![](E:\\人工智能\\Snipaste_2026-05-12_08-58-36.png)', 'cfff7f98a1bcab15907802407a830b534fa919691de9908153dfb8244b8a1987', '{\"section\": \"梯度下降法\"}', 31, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:67:df774021e127eb24', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 67, '### 一元梯度下降(单变量梯队下降)\n\n![](E:\\人工智能\\Snipaste_2026-05-12_09-40-36.png)\n\n学习率不能太大,太大会容易错过最低点会导致梯度爆炸或梯度震荡，太小会导致步数会增加很多\n\n![](E:\\人工智能\\Snipaste_2026-05-12_09-50-55.png)', 'df774021e127eb24a7cdced1f6cbe08d3c45a33b309642566dc366595fa11dbd', '{\"section\": \"一元梯度下降(单变量梯队下降)\"}', 109, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:68:411ded888ec88082', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 68, '### 多变量梯度下降\n\n![](E:\\人工智能\\Snipaste_2026-05-12_10-52-38.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-12_10-58-30.png)\n\n当学习率是10时算出来的结果是-19\n\n导致过大\n\n从而错过最低值\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-12_11-07-24.png\" style=\"zoom:67%;\" />', '411ded888ec88082a708a777e1a377e1bf06e881af6e954c09e77ea561085a30', '{\"section\": \"多变量梯度下降\"}', 121, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:69:0c9fc332d047fb68', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 69, '### 梯度下降分类\n\n![](E:\\人工智能\\Snipaste_2026-05-15_11-06-27.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-15_11-12-20.png)\n\n随机平均梯度下降算法SAG\n\n该算法就像中医行业,一开始怎么都很不顺,后面学习越多,后面就越考越吃香\n\n目前使用较多的是:小批量梯度下降\n\n![](E:\\人工智能\\Snipaste_2026-05-15_11-41-04.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-15_11-44-08.png)', '0c9fc332d047fb681dab6be9e3b1f613745a780fde88ce61897d5e8a3869c8c7', '{\"section\": \"梯度下降分类\"}', 167, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:7:4da3a595fad94961', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 7, '## pandas\n\n![](E:\\人工智能\\Snipaste_2026-04-13_22-54-15.png)\n\nmatplotlib\n\n![](E:\\人工智能\\Snipaste_2026-04-13_22-58-07.png)', '4da3a595fad949616eaedfcd6cd3514abe15aaf1ae000fd130ad2cf24ceeb09b', '{\"section\": \"pandas\"}', 52, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:70:17be98fa00da4905', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 70, '## 线性回归模型评估\n\n![](E:\\人工智能\\Snipaste_2026-05-16_09-38-19.png)\n\n评估例子\n\n![](E:\\人工智能\\Snipaste_2026-05-16_09-45-51.png)\n\n(1,3)点                               MAE=2                  RMSE=2.236            RMSE>MAE\n\n再举个例子\n\n![](E:\\人工智能\\Snipaste_2026-05-16_09-47-07.png)\n\n一般使用:MAE 和 RMSE 这两个指标\n\n​	MAE反应的是“**真实”的平均误差**，RMSE会将误差大的数据点放大\n\n​	MAE不能提现出误差大的数据点，RMSE放大大误差的数据点对指标的影响，但是对异常数据比较敏感\n\n综合来说\n\n​	都能反映出预测值和真实值之间的误差\n\n​	MAE对误差大小不敏感\n\n​	RMSE会放大预测误差较大的误差\n\n​	RMSE对异常数据敏感\n\n欠拟合与过拟合   -    出现原因和解决方案\n\n![](E:\\人工智能\\Snipaste_2026-05-18_20-44-34.png)\n\n在训练集上表现不好,在测试集上表现也不好\n\n解决办法，继续学习\n\n1.添加其他特征选项\n\n2.添加多项式特征\n\n![](E:\\人工智能\\Snipaste_2026-05-18_20-45-13.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-18_20-49-32.png)\n\n在训练集上表现好,在测试集上表现不好\n\n解决方法\n\n​	1.重新清洗数据集\n\n​	2.增大数据的训练量\n\n​	3.正则化\n\n​	4.减少特征维度', '17be98fa00da490535cf3ad38fb292604f6d6b0011e50b94347f22671e9ca3d5', '{\"section\": \"线性回归模型评估\"}', 446, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:71:fcba801682ce4838', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 71, '#### L1正则化\n\n![](E:\\人工智能\\Snipaste_2026-05-18_21-00-45.png)\n\n无限趋于0从而达到 **特征选择的目的**\n\n```python', 'fcba801682ce4838e58c049e32dd87202bddfeb89aeec3330feb7c4a379ad53b', '{\"section\": \"L1正则化\"}', 56, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:72:f079e50ac4fe862e', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 72, '# 改为创建L1正则化对象\n    estimator = Lasso(alpha=0.01)  # alpha:正则化系数(惩罚系数),默认是1     惩罚越大,权重越小\n```\n\n![](E:\\人工智能\\Snipaste_2026-05-18_22-57-56.png)', 'f079e50ac4fe862e7e6d19352766ae5528dfda1acf2cebccf924695811e1d483', '{\"section\": \"改为创建L1正则化对象\"}', 76, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:73:6f6772d4434b8e1c', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 73, '#### L2正则化\n\n![](E:\\人工智能\\Snipaste_2026-05-18_21-05-09.png)\n\n```python', '6f6772d4434b8e1cad15a4b23aa3129c70bdae32ed13e7f4a23db5dc1f588033', '{\"section\": \"L2正则化\"}', 36, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:74:b35a6c764d392709', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 74, '# 改为创建L2正则化对象\n    estimator = Ridge(alpha=10)      # alpha:正则化系数(惩罚系数),默认是1     惩罚越大,权重越小\n```\n\n惩罚系数不一样,拟合效果就有差别\n\n![](E:\\人工智能\\Snipaste_2026-05-18_22-56-01.png)\n\n区别:\n\nL1和L2的本质区别是L1可以让权重系数等于0\n\nL2能无限的趋向于0        但是不会为0\n\n L1和L2都是基于惩罚系数 来修改(特征列的)权重的,惩罚系数越大,则修改力度就越大,对应的权重就越小(惩罚力度大权重就变小咯)\n\n大白话:我要去爬山,带了个小包,装了：登山杖，水，面包，衣服，雨伞，鞋子......        发现包装不下了\n\nL1正则化：可以实现去掉一些不是必选的。例如：当天去，当天回，且天气晴朗 ---->可以不带雨伞，鞋子， 即：权重为0\n\nL2正则化：换一个非常非常大的包，还是那些物品，但是空间占用(权重)就变小........\n\n![](E:\\人工智能\\Snipaste_2026-05-18_23-05-06.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-18_23-07-19.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-18_23-10-18.png)\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-18_23-13-12.png\" style=\"zoom:150%;\" />', 'b35a6c764d39270967cd23ad144570d8e420931e2c83f12680bc0c02e0fd3989', '{\"section\": \"改为创建L2正则化对象\"}', 446, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:75:d610f4ea0d0dc47f', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 75, '## 逻辑回归概念\n\n逻辑回归:有监督学习,有特征,有标签,且标签是离散的(分类)\n\n适用于二分类以及三分类啊或多分类这样\n\n原理:数据经过线性回归处理过得到的预测值丢到Sigmoid激活函数,这个激活函数会把这个值映射到概率0~1区间,然后结合你写的阈值进行分类     就是按照下面例如那样分类\n\n例如\n\n这个值 >0,6   就是A类\n\n小于这个值就是B类\n\n![](E:\\人工智能\\Snipaste_2026-05-19_00-14-16.png)\n\n混淆矩阵\n\n![](E:\\人工智能\\Snipaste_2026-05-19_00-17-32.png)\n\nT(True)：真\n\nF(False):假\n\nPositive:正例\n\nNegative:反例\n\n精确率:  tp/(tp+fp)\n\n召回率:tp/(tp+fn)\n\n**F1-score** 是分类问题中综合评价模型性能的指标，它结合了**精确率（Precision）**和**召回率（Recall）**\n\n计算公式\n$$\nF1=2×{Precision×Recall}/{Precision+Recall}\n$$\n*F*1=2×{精确率×召回率/精确率+召回率}\n\n如果精确率或召回率为 0，则 F1 = 0；如果两者均为 1，则 F1 = 1。\n\n示例:\n\n假设有 100 个正例，模型预测出 80 个正例，其中 60 个是正确的：\n\n- 精确率 = 60 / 80 = 0.75\n- 召回率 = 60 / 100 = 0.60\n- F1 = 2 * (0.75 * 0.60) / (0.75 + 0.60) = 2 * 0.45 / 1.35 = 0.6667\n\n直观理解：F1 是精确率和召回率的“平衡点”，在两者都重要时（如信息检索', 'd610f4ea0d0dc47f3765e522faa2633d2f39a066876f11c7460e6f5871a63784', '{\"section\": \"逻辑回归概念\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:76:5f8b9f0fe317d7dd', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 76, '= 60 / 100 = 0.60\n- F1 = 2 * (0.75 * 0.60) / (0.75 + 0.60) = 2 * 0.45 / 1.35 = 0.6667\n\n直观理解：F1 是精确率和召回率的“平衡点”，在两者都重要时（如信息检索、医疗诊断）优先使用。\n\n逻辑回归是做分类的不能用之前的线性回归的准确率来预测\n\n比如:一个医院告诉下面患者有准确率97%是阳性,那下面也不知道具体谁阳性,都会以为自己没阳性\n\n应该告诉精确哪个人没阳性,所以要精确率不能靠准确率\n\n![](E:\\人工智能\\Snipaste_2026-05-21_00-18-02.png)', '5f8b9f0fe317d7dd78a3b977adbcb82623fc8607d6534c739b3f5c300f003bc1', '{\"section\": \"逻辑回归概念\"}', 211, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:77:2df6890756cc524d', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 77, '### 损失函数', '2df6890756cc524de06373d78ed0c7b129005093ede85e9f455386354a8800f7', '{\"section\": \"损失函数\"}', 7, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:78:be85a460aedaf244', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 78, '#### 极大似然估计\n\n通俗说极大似然估计就是极大值       加个负号就是极小值\n\n根据你抽取样本的分布来预测你测试你整体数据的分布\n\n通过极大化概率事件,来估计最优参数', 'be85a460aedaf2442f4c747a7fd94e31a4435cf508fc0f1acb14055ff552dcad', '{\"section\": \"极大似然估计\"}', 74, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:79:c609d2265b14c7b2', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 79, '### 对数函数\n\n![](E:\\人工智能\\Snipaste_2026-05-22_22-53-38.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-22_22-54-27.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-22_22-55-20.png)\n\n线性回归原理\n\n![](E:\\人工智能\\Snipaste_2026-05-23_11-29-49.png)\n\n例子\n\n![](E:\\人工智能\\Snipaste_2026-05-23_11-36-49.png)\n\n逻辑回归原理---损失函数\n\n![](E:\\人工智能\\Snipaste_2026-05-23_12-05-19.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-23_12-05-19.png)\n\n概率值越大值越是正样本\n\n![](E:\\人工智能\\Snipaste_2026-05-23_14-16-17.png)\n\n<img src=\"E:\\人工智能\\Snipaste_2026-05-23_14-16-43.png\" style=\"zoom:100%;\" />\n\n![](E:\\人工智能\\Snipaste_2026-05-23_14-22-30.png)\n\n逻辑回归API函数和案例\n\n![](E:\\人工智能\\Snipaste_2026-05-24_21-41-58.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-24_21-46-35.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-24_21-44-50.png)\n\n```python\nimport numpy as np\nimport pandas as pd\nfrom sklearn.linear_model import LogisticRegression  #逻辑回归模型\nfrom sklearn.preprocessing import StandardScaler #标准化\nfrom sklearn.model_selection import train_test_split  #训练集和测试集分割\nfrom sklearn.metrics import accuracy_score   #模型评估\n\n#1.加载数据\ndata = pd.read_csv(\'./data/breast-cancer-wisconsin.csv\')\ndata.info()    #查看数据信息\n\n#2.数据预处理\n#2.1把 ? 替换成 np.nan (这个就是换', 'c609d2265b14c7b2d55634fdbf6aea83386d0e4baa98a8ecc419faff7a65b82f', '{\"section\": \"对数函数\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:8:61f1d8b417041227', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 8, '## serborn\n\n![](E:\\人工智能\\Snipaste_2026-04-13_22-59-40.png)', '61f1d8b41704122701f7fa65fca346a51fd95abfaadbfde57e359a247eec3f93', '{\"section\": \"serborn\"}', 27, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:80:f662ee5bcf1cd1d7', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 80, '试集分割\nfrom sklearn.metrics import accuracy_score   #模型评估\n\n#1.加载数据\ndata = pd.read_csv(\'./data/breast-cancer-wisconsin.csv\')\ndata.info()    #查看数据信息\n\n#2.数据预处理\n#2.1把 ? 替换成 np.nan (这个就是换成null)  参1:要被替换的值  参2:用来替换的值  参3:是否替换源数据,默认False\ndata.replace(\'?\',np.nan,inplace=True)\n#2.2缺失值处理  --->  删除     要么删除,要么填写\ndata.dropna(axis=0,inplace=True) #axio=0 表示行, 1表示列   删除包含缺失值的行\n#2.3答应处理后的信息', 'f662ee5bcf1cd1d74132fc9e3902f9654800c1022b7b7c7e6d084fc9f8ce51c7', '{\"section\": \"对数函数\"}', 200, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:81:367c94ad38c65a2a', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 81, '# data.info()\n\n#3特征工程  (1.特征提取    2.特征预处理  )\n#3.1特征提取之  提取特征和标签\nx = data.iloc[:,1:-1] #按照行号,列索引获取数据,   :表示所有行   1:-1表示从第1列到最后1列, 包左不包右\ny = data.iloc[:,-1]  #获取最后一列', '367c94ad38c65a2a42b2740996a7e18d9beffe6abf7375b83f73c8c32b9ba4b7', '{\"section\": \"data.info()\"}', 115, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:82:5bc140ac553f382f', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 82, '# y = data[\'Class\']    #获取最后一列,效果跟上一行一样', '5bc140ac553f382f396c5eea576e7f2f2cdb27102a1497a5c360c43c2e9e3bb7', '{\"section\": \"y = data[\'Class\']    #获取最后一列,效果跟上一行一样\"}', 25, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:83:51bc66e8ecf1ad1a', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 83, '# y = data.Class       #获取最后一列,效果跟上一行一样\n\n#3.2查看下特征 和 标签\nprint(x[:5])\nprint(y[:5])\nprint(x.shape,y.shape)\n#3.3切割训练集和测试集\nx_train,x_test,y_train,y_test = train_test_split(x,y,test_size=0.2,random_state=23)\n#3.4特征工程:标准化\n#3.4.1创建标准化对象\ntransfer = StandardScaler()\n#3.4.2对训练集进行标准化    训练+标准化\nx_train = transfer.fit_transform(x_train)\n#3.4.3 对测试集进行标准化  标准化\nx_test = transfer.transform(x_test)\n\n#4.模型训练\n#4.1创建逻辑回归对象\nestimator = LogisticRegression()\n#4.2模型训练\nestimator.fit(x_train,y_train)\n\n#5.模型预测\ny_pre = estimator.predict(x_test)\nprint(f\'预测值为:{y_pre}\')\n\n#6.模型评估\n#正确率(准确率),公式为: 预测值 / 样本总数\nprint(f\'预测前评估,正确率::{estimator.score(x_test,y_pre)}\')  #测试集的特征,标签\nprint(f\'预测后评估,正确率::{accuracy_score(y_test,y_pre)}\')   #测试集的标签,预测值\n```\n\n预处理这一块要注意\n\n2.数据预处理\n2.1把 ? 替换成 np.nan (这个就是换成null)  参1:要被替换的值  参2:用来替换的值  参3:是否替换源数据,默认False\ndata.replace(\'?\',np.nan,inplace=True)\n2.2缺失值处理  --->  删除     要么删除,要么填写\ndata.dropna(axis=0,inplace=True) #axio=0 表示行, 1表示列   删除包含缺失值的行\n\n现在只是', '51bc66e8ecf1ad1abc7266f8a9b5f15def5f634e3a309b6e7a6173339afe737a', '{\"section\": \"y = data.Class       #获取最后一列,效果跟上一行一样\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:84:4d27df01aebf412a', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 84, ',默认False\ndata.replace(\'?\',np.nan,inplace=True)\n2.2缺失值处理  --->  删除     要么删除,要么填写\ndata.dropna(axis=0,inplace=True) #axio=0 表示行, 1表示列   删除包含缺失值的行\n\n现在只是用正确率(准确率)来评估,但是结果不精准\n\n因为逻辑回归模型主要用于二分类\n\n例如: A类还是B类  不能说97%是A类   3%是B类\n\n所以要通过 混淆矩阵来评测   即:**精确率,召回率 ,F1值(F1-Score),Roc曲线,AUC值**\n\n分类评估方法    混淆矩阵\n\n![](E:\\人工智能\\Snipaste_2026-05-24_23-41-49.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-25_12-13-52.png)\n\nROC曲线、AUC曲线\n\n![](E:\\人工智能\\Snipaste_2026-05-27_21-42-19.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_21-45-57.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_22-57-56.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_22-59-24.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_23-05-07.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_23-05-46.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-27_23-06-00.png)', '4d27df01aebf412ae5216c1c7658dbe4437e0f728e92d4386d729a2ce561bd45', '{\"section\": \"y = data.Class       #获取最后一列,效果跟上一行一样\"}', 410, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:85:54740a586e396186', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 85, '### 逻辑回归_电信用户流失预测案例\n\n![](E:\\人工智能\\Snipaste_2026-05-28_21-17-09.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-29_10-33-46.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-29_10-53-45.png)\n\n在数据集中，`Churn`（客户是否流失）和 `gender`（性别）这两列是文本类型的字符串（比如 `\'Yes\'`/`\'No\'` 和 `\'Male\'`/`\'Female\'`），而大多数机器学习模型（比如逻辑回归）只能处理数值型数据。因此，需要把这些字符串转换成数字形式。\n\n**One‑Hot 编码（独热编码）**就是常用的一种转换方法。它会为每个类别创建一个新的 0/1 列，比如：\n\n- 对于 `gender`：原来一列变成两列 `gender_Male` 和 `gender_Female`。如果某行是 `\'Male\'`，则 `gender_Male = 1`，`gender_Female = 0`。\n- 对于 `Churn`：变成两列 `Churn_Yes` 和 `Churn_No`（不过在逻辑回归中，`Churn` 通常作为目标变量，可以简单地映射为 0/1：`\'Yes\'→1`，`\'No\'→0`）。\n\n```python\ndef dm03_logistic_regression():\n    #1.加载数据\n    churn_df = pd.read_csv(\'./data/churn.csv\')\n    #2.加载数据\n    #2.1对object类型的数据的列(数据)做one-hot编码处理\n    churn_df = pd.get_dummies(churn_df,columns=[\'Churn\',\'gender\'])\n    #2.2删除one-hot处理后的冗余列\n    churn_df.drop([\'Churn_No\', \'gender_Male\'], axis=1, inplace=True)\n    #2.3修改列名,将Churn_Yes -', '54740a586e39618686c96f04cc732805e338eba80f1042c72199ed04ab419465', '{\"section\": \"逻辑回归_电信用户流失预测案例\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:86:60631e4e024f48a3', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 86, '据)做one-hot编码处理\n    churn_df = pd.get_dummies(churn_df,columns=[\'Churn\',\'gender\'])\n    #2.2删除one-hot处理后的冗余列\n    churn_df.drop([\'Churn_No\', \'gender_Male\'], axis=1, inplace=True)\n    #2.3修改列名,将Churn_Yes ---->flag   充当标签列\n    churn_df.rename(columns={\'Churn_Yes\':\'flag\'},inplace=True)\n    #2.4特征提取和标签列\n    x = churn_df[[\'Contract_Month\',\'internet_other\',\'PaymentElectronic\']]\n    y = churn_df[\'flag\']    #False---->不流失, True---->流失\n    #2.5划分训练集和测试集\n    x_train,x_test,y_train,y_test = train_test_split(x,y,test_size=0.3,random_state=70)\n\n    #3特征工程(列如:特征提取,特征预处理----->归一化，标准化....),暂不处理\n\n    #4.模型训练\n    #4.1创建(逻辑回归)模型对象\n    estimator = LogisticRegression()\n    #4.2模型训练\n    estimator.fit(x_train,y_train)\n    #5.模型预测\n    y_pre = estimator.predict(x_test)\n    print(f\'预测值为:{y_pre}\')\n    #6.模型评估\n    print(f\'准确率:{estimator.score(x_test,y_pre)}\')\n    print(f\'准确率:{accuracy_score(y_test,y_pre)}\')\n\n    print(f\'精确率:{precision_score(y_test,y_pre)}\')\n    print(f\'召回率:{recall_score(y_test,y_pre)}\')\n\n    print(f\'F1值:{f1_score(y_test,y_pre)}\')\n\n    #macro avg:宏平均  即：不考虑样本权重,直接求平均  适用于:数据均衡的情况\n    #weighted avg:样本权重平均  即：考虑样本权重,求平均  适用于:数据不均衡的情况\n    print(f\'分类评估报告:{classification_report(y_test', '60631e4e024f48a3ab79fc90957ee9cc80b837ee626a3cf3bed2c78f6a1f7092', '{\"section\": \"逻辑回归_电信用户流失预测案例\"}', 500, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:87:dd0c2a04a559acb0', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 87, 'avg:宏平均  即：不考虑样本权重,直接求平均  适用于:数据均衡的情况\n    #weighted avg:样本权重平均  即：考虑样本权重,求平均  适用于:数据不均衡的情况\n    print(f\'分类评估报告:{classification_report(y_test,y_pre)}\')\nif __name__ == \'__main__\':\n    # dm01_data_preprocess()\n    # dm02_data_visualization()\n    dm03_logistic_regression()\n```', 'dd0c2a04a559acb04d683bb2428d997c6f783be40e02534156b14447e45fa7a9', '{\"section\": \"逻辑回归_电信用户流失预测案例\"}', 108, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:88:5231bee771537682', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 88, '#### 2.1 对 object 类型的列做 one-hot 编码处理\n\npython\n\n运行\n\n```\nchurn_df = pd.get_dummies(churn_df,columns=[\'Churn\',\'gender\'])\n```\n\n- **核心作用**：把文本 / 分类类型的`object`数据，转换成模型可识别的数值型数据。\n\n- **原理说明**：逻辑回归是广义线性模型，**只能处理数值型输入，无法直接读取文本 / 分类数据**。原始数据中，`Churn`列的取值是`Yes/No`（是否流失）、`gender`列的取值是`Male/Female`（性别），都是典型的二分类文本变量，必须通过编码转换成数值。\n\n- one-hot 编码的结果\n\n  ：\n\n  - `Churn`列会被拆分为 2 列：`Churn_Yes`（1 = 是，0 = 否）、`Churn_No`（1 = 是，0 = 否）\n  - `gender`列会被拆分为 2 列：`gender_Male`（1 = 男性，0 = 女性）、`gender_Female`（1 = 女性，0 = 男性）', '5231bee7715376822ab49658da841ffb228d0b847ed587057b6ced5c807d79db', '{\"section\": \"2.1 对 object 类型的列做 one-hot 编码处理\"}', 299, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:89:ca85ec9f776e36b4', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 89, '#### 2.2 删除 one-hot 处理后的冗余列\n\npython\n\n运行\n\n```\nchurn_df.drop([\'Churn_No\', \'gender_Male\'], axis=1, inplace=True)\n```\n\n- **核心作用**：消除 one-hot 编码带来的**完全多重共线性**问题，保证线性模型的正常求解。\n\n- 为什么这两列是冗余的\n\n  ：对于二分类变量的 one-hot 编码，生成的两列是\n\n  100% 线性相关\n\n  的。比如：\n\n  - 当`Churn_Yes=1`时，`Churn_No`必然 = 0；当`Churn_Yes=0`时，`Churn_No`必然 = 1\n  - 当`gender_Female=1`时，`gender_Male`必然 = 0；当`gender_Female=0`时，`gender_Male`必然 = 1\n\n- **不删除的严重后果**：完全多重共线性会导致线性模型（逻辑回归）的参数估计不稳定、无法求解，甚至出现奇异矩阵，最终模型完全无法训练，或者训练出的结果完全无意义。\n\n- **行业最佳实践**：对于 n 分类的 one-hot 编码，最终只保留 n-1 列，二分类变量只保留 1 列，这是线性模型预处理的通用规范。', 'ca85ec9f776e36b4b4de003a71e18ee64cfbdc06b41885d8e466886f8d29d6de', '{\"section\": \"2.2 删除 one-hot 处理后的冗余列\"}', 345, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:9:08996153ff26a6bf', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 9, '## SKlearn\n\n![](E:\\人工智能\\Snipaste_2026-04-13_23-01-43.png)', '08996153ff26a6bf43a1aeeb6b65ea0b18e24d2221cdb35c93a808ab9c1a6259', '{\"section\": \"SKlearn\"}', 27, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:90:9fd32ae5c9ed9d85', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 90, '#### 2.3 修改列名，将 Churn_Yes 改为 flag，充当标签列\n\npython\n\n运行\n\n```\nchurn_df.rename(columns={\'Churn_Yes\':\'flag\'},inplace=True)\n```\n\n- **核心作用**：统一标签列的命名规范，明确列的业务语义，符合机器学习代码的通用写法。\n\n- 为什么要改列名\n\n  ：\n\n  1. **语义更通用**：`flag`是二分类任务中标签列的通用命名，代表「是否发生目标事件」，这里就是「是否流失」，比`Churn_Yes`更简洁、更符合行业惯例，后续代码的可读性更强。\n  2. **明确标签属性**：重命名后，能清晰区分「标签列（要预测的目标）」和「特征列（用来预测的输入）」，避免在后续训练、评估中混淆列的用途。\n  3. **代码复用性更强**：如果后续更换预测目标（比如预测是否续费、是否活跃），只需要修改重命名的列名，不需要改动后续所有用到标签列的代码。', '9fd32ae5c9ed9d8560af24d501cd8630cd578082ac62677f9d99ded7dacd4068', '{\"section\": \"2.3 修改列名，将 Churn_Yes 改为 flag，充当标签列\"}', 327, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:91:a39bcab1932002c8', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 91, '#### 2.4 特征提取和标签列拆分\n\npython\n\n运行\n\n```\nx = churn_df[[\'Contract_Month\',\'internet_other\',\'PaymentElectronic\']]\ny = churn_df[\'flag\']\n```\n\n- **核心作用**：把数据集拆分为「特征矩阵 x」和「标签向量 y」，这是模型训练的标准输入格式。\n\n- 基础定义\n\n  ：\n\n  - 特征（x）：模型用来预测目标的输入变量，是影响最终结果的核心因素\n  - 标签（y）：模型要预测的输出结果，是本次任务的核心预测目标\n\n------', 'a39bcab1932002c86a8e0b201676bdb546d366fd960224a3cb8277c81114b1e3', '{\"section\": \"2.4 特征提取和标签列拆分\"}', 174, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:92:971268a373fb44d8', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 92, '#### 三、核心疑问深度解答', '971268a373fb44d881dad1bd2ce6aec54a52b6ac01ddee63c83fcf74f4302266', '{\"section\": \"三、核心疑问深度解答\"}', 14, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:93:6817127c6ae52c23', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 93, '#### 1. 为什么 y 列只能是 flag，不能是其他列？\n\n因为`flag`列是本次二分类任务的**唯一预测目标**，它的取值是 0/1，完全符合二分类任务的标签要求：\n\n- `flag=0`：对应`Churn_No`，代表用户**不流失**，是负样本\n- `flag=1`：对应`Churn_Yes`，代表用户**流失**，是正样本\n\n整个模型的训练目标，就是学习特征和「是否流失」之间的映射关系，所以标签列必须是这个代表流失结果的`flag`列，其他列都是用来预测的特征，不能作为标签。', '6817127c6ae52c2382e36f043030c8a1fac7d568c63a81200849c636cb778ff4', '{\"section\": \"1. 为什么 y 列只能是 flag，不能是其他列？\"}', 203, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:94:e0e68825a63f8ee6', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 94, '#### 2. 为什么特征 x 只提取这 3 列，不是全部列？\n\n选择这 3 列作为特征，是**业务逻辑 + 数据特性 + 模型要求**共同决定的，核心原因有 3 点：\n\n1. 业务强相关性\n\n   ：这 3 列都是和用户流失高度相关的核心业务特征，是行业内预测客户流失的通用关键指标：\n\n   - `Contract_Month`：合同期限 / 签约月份，合同期限越长，用户粘性越高，流失概率越低，是流失预测的第一核心特征\n   - `internet_other`：是否使用其他互联网附加服务，用户使用的附加服务越多，对产品的依赖度越高，流失概率越低\n   - `PaymentElectronic`：是否使用电子支付方式，电子支付用户的活跃度、留存意愿通常更高，是流失预测的重要行为特征\n\n2. **数据已符合模型输入要求**：这 3 列都是已经处理好的数值型 / 二值型变量，不需要再做额外的编码、清洗处理，可以直接输入到逻辑回归模型中，避免了额外的预处理工作量。\n\n3. **避免噪声与过拟合**：选择经过业务验证的核心特征，而不是全部列，能剔除无关特征带来的随机噪声，提升模型的训练效率，同时避免模型学习到无关的随机规律，导致过拟合（训练集效果好，测试集效果差）。', 'e0e68825a63f8ee6958de5bfc4501deb4c8145cb81ce017332395f118db87dc4', '{\"section\": \"2. 为什么特征 x 只提取这 3 列，不是全部列？\"}', 442, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:95:dcca25e40d6f504a', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 95, '### 决策树\n\n决策树:根据你的某些特征和信息来做为根节点,往下划分子集的过程就叫做决策树\n\n决策树属于有监督学习\n\nID3：信息增益\n\n熵-条件熵=信息增益\n\nC4.5：信息增益率\n\nCART决策树：Gini 、基尼值\n\n![](E:\\人工智能\\Snipaste_2026-05-30_12-40-14.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-30_11-35-25.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-30_12-33-12.png)', 'dcca25e40d6f504a884167ebf3a611b84616a1d8715b68a84cd7d08118ee50ba', '{\"section\": \"决策树\"}', 160, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:96:4d205a8ca96287e3', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 96, '#### 信息熵\n\n熵：信息论中代表随机变量不确定度的度量\n\n你的数据越完整代表熵越大\n\n你的数据越乱代表熵越小\n\n![](E:\\人工智能\\Snipaste_2026-05-31_10-54-46.png)\n$$\n(信息)熵 = -∑分类占比 * log{_2}(分类占比)\n$$\n\n$$\n(信息)熵 = -∑p(x_{i}) * log{_2}p(x_{i})\n$$\n\n$$\np(x_{i})就是分类占比的意思\n$$\n\n![](E:\\人工智能\\Snipaste_2026-05-31_11-12-24.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-31_11-25-56.png)', '4d205a8ca96287e3a0d9584fce70017c4a96742c49d7496ea347682d938edc85', '{\"section\": \"信息熵\"}', 199, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:97:2bfeb7c6c2b5e01f', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 97, '#### 条件熵\n\n![](E:\\人工智能\\Snipaste_2026-05-31_12-06-33.png)\n\n![](E:\\人工智能\\Snipaste_2026-05-31_12-08-06.png)', '2bfeb7c6c2b5e01f1abbd5e264f3be0e1a6e8babcc4f90af57328900f079a02a', '{\"section\": \"条件熵\"}', 55, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:98:3b72fd01ade0a8c1', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 98, '#### ID3决策树\n\n![](E:\\人工智能\\Snipaste_2026-05-31_12-10-22.png)\n\n![](E:\\人工智能\\Snipaste_2026-06-02_22-52-08.png)\n\n计算信息增益最大的是活跃度的信息增益最大,所以活跃度当决策树的第一个节点\n\n信息增益=信息熵-条件熵\n\n![](E:\\人工智能\\Snipaste_2026-06-02_23-02-19.png)\n\n弊端：分类越多越容易成为根节点\n\n要想解决这个弊端就用C4.5决策树', '3b72fd01ade0a8c15cc13bd1b2517150c4b37187678d7e3f8a3b1d26d331af26', '{\"section\": \"ID3决策树\"}', 159, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('1a226d28-4a18-42a4-830b-9b326dc20d91:v1:99:df2985dd6f4cc628', '1a226d28-4a18-42a4-830b-9b326dc20d91', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 99, '#### C4.5决策树\n\nC4.5= 信息增益  /  特征熵\n\n信息增益率 = 信息增益 / 特征熵\n\n![](E:\\人工智能\\Snipaste_2026-06-02_23-39-53.png)\n\n![](E:\\人工智能\\Snipaste_2026-06-08_11-34-30.png)\n\n单算目标的熵就是信息熵\n\n特征结合目标值一起来算熵就是条件熵\n\n单算特征熵就是特征熵\n\n![](E:\\人工智能\\Snipaste_2026-06-08_11-06-18.png)\n\n特征熵 = 惩罚系数\n\n计算特征熵\n\n![](E:\\人工智能\\Snipaste_2026-06-08_11-36-24.png)\n\n![](E:\\人工智能\\Snipaste_2026-06-08_11-55-55.png)\n\n分类越多那么信息增益就越大\n\n优先使用信息增益率高的,所以再划分的时候用特征a划分\n\n结论:特征a的信息增益率大于特征b的信息增益率,根据信息增益率,应该选择特征a做为分类特征\n\n![](E:\\人工智能\\Snipaste_2026-06-08_12-08-46.png)\n\n![](E:\\人工智能\\Snipaste_2026-06-08_12-10-46.png)\n\nc4.5信息增益率越大越好', 'df2985dd6f4cc6289a8d9c7266df53baae191f6dab25767c16f52f71168a6410', '{\"section\": \"C4.5决策树\"}', 351, '2026-06-21 04:59:06');
INSERT INTO `kb_chunks` VALUES ('2120f655-b683-4d5b-9802-efeb1ce850cd_chunk_0', '2120f655-b683-4d5b-9802-efeb1ce850cd', 'e9788ee0-27b2-43ac-b6bb-3266db8f591b', 6, 0, 'Python是一种高级编程语言，由Guido van Rossum于1991年创建。Python以简洁易读的语法著称，广泛应用于Web开发、数据分析、人工智能等领域。Python的设计哲学强调代码的可读性和简洁性。', '6893a8f2e735d76513c32c5b4ffc9e126c8bae8f146372b21f24d7778ad88eb2', '{}', 107, '2026-06-06 07:05:35');
INSERT INTO `kb_chunks` VALUES ('360719ac-0b5f-442c-ae98-ba202ec237b7:v1:0:58d4d5b1a07da87c', '360719ac-0b5f-442c-ae98-ba202ec237b7', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 0, '讲义：https://www.yuque.com/zhangzhijun-91vgw/javaai1.0?# 《Java+AI智能应用开发（线上训练营）v1.0》 密码：nxyt', '58d4d5b1a07da87c57e1fcf77d75583d95b5a964d051a2eec08736fd7db51013', '{\"section\": null}', 47, '2026-06-21 04:57:53');
INSERT INTO `kb_chunks` VALUES ('6b2d59c0-ff65-4676-9388-22a940279296:v1:0:25dd88dab6418b86', '6b2d59c0-ff65-4676-9388-22a940279296', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 0, '# 11\n\n**5. 文件上传 + 分析（核心差异化）**\n\n用户上传 PDF、Word、Excel，AI 直接分析。这结合你已有的 RAG 体系，是最大亮点。\n\njava\n\n```java\n// 后端接收文件，动态写入向量库\n@PostMapping(\"/upload\")\npublic Result<?> uploadDocument(@RequestParam MultipartFile file,\n                                 @RequestParam String sessionId) {\n    // 解析文件 → 切片 → 向量化 → 存入用户专属的 Redis namespace\n}\n```\n\n**6. 知识库管理页面**\n\n让用户自己上传文档建立私有知识库，这是 ChatGPT 免费版没有的功能。\n\n```\n我的知识库\n├── 公司规章制度.pdf  ✓\n├── 产品手册v2.docx  ✓\n└── 竞品分析报告.xlsx ✓\n\n[+ 上传文档]\n```\n\n**7. 提示词模板市场**\n\n预设场景模板，降低用户使用门槛：\n\n```\n📝 合同审查    🔍 竞品分析\n📊 数据解读    💡 头脑风暴\n📧 邮件撰写    🐛 代码调试\n```\n\n**8. 对话分享**\n\n生成分享链接，让用户把好的对话分享给同事，这是增长的关键。\n\n------', '25dd88dab6418b86498875c43f980420981533dbbeb9c41db0fa5fa19356733d', '{\"section\": \"11\"}', 334, '2026-06-21 04:59:08');
INSERT INTO `kb_chunks` VALUES ('6b2d59c0-ff65-4676-9388-22a940279296:v1:1:c0b44c2f2408daaa', '6b2d59c0-ff65-4676-9388-22a940279296', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 1, '### 第三阶段：商业化功能（4-6个月）\n\n**9. 积分/会员体系**\n\n```\n免费版：每天 20 次对话，不能上传文件\nPro版：无限对话 + 文件上传 + 私有知识库\n企业版：私有部署 + API 接入 + 多人协作\n```\n\n**10. 团队协作**\n\n共享知识库、共享对话、@同事，打企业内部工具市场。\n\n**11. API 开放**\n\n让开发者调用你的服务，收 Token 费用。\n\n------', 'c0b44c2f2408daaac7a82ecce11390d2402e1b7c7a2c95447ce93649836eeb47', '{\"section\": \"第三阶段：商业化功能（4-6个月）\"}', 157, '2026-06-21 04:59:08');
INSERT INTO `kb_chunks` VALUES ('6b2d59c0-ff65-4676-9388-22a940279296:v1:2:bf7b901397ceab21', '6b2d59c0-ff65-4676-9388-22a940279296', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 2, '## 四、技术优化清单\n\n**后端优化**\n\n| 问题           | 当前状况             | 优化方案                                   |\n| -------------- | -------------------- | ------------------------------------------ |\n| 流式响应编码   | 可能有乱码           | 明确设置 `text/event-stream;charset=UTF-8` |\n| 没有限流       | 单用户可打爆服务     | 加 Redis 限流，每分钟最多 20 次            |\n| 向量库每次重建 | `store()` 方法被注释 | 启动时检查是否已有数据，有则跳过           |\n| 没有异常监控   | 出错只打日志         | 接入 Sentry 或钉钉/企微告警                |\n\n**前端优化**\n\n| 问题             | 优化方案                           |\n| ---------------- | ---------------------------------- |\n| 无 Markdown 渲染 | 引入 marked + highlight.js         |\n| 打字机效果卡顿   | 当前逐字符显示性能差，改为逐词显示 |\n| 无骨架屏         | 加载时显示骨架，减少白屏感知       |\n| 不支持移动端     | 响应式布局适配，或做 PWA           |\n\n------', 'bf7b901397ceab21a8dece29586bbada035a9eb5606485076f7ec786bfc42aa1', '{\"section\": \"四、技术优化清单\"}', 394, '2026-06-21 04:59:08');
INSERT INTO `kb_chunks` VALUES ('6b2d59c0-ff65-4676-9388-22a940279296:v1:3:837ab7d6024abe14', '6b2d59c0-ff65-4676-9388-22a940279296', '3354ccbc-ec69-4939-b133-648140d674e4', 14, 3, '## 五、最重要的一点\n\n技术只是门槛，**真正留住用户靠的是垂直场景的数据积累**。\n\n你喂进 RAG 的专业文档质量，决定了你的产品天花板。ChatGPT 的通用性是它的优势，也是它的弱点——它不会比一个喂了 10000 份行业合同的法律 AI 更懂法律。\n\n**建议的最小闭环路径：**\n\n选一个垂直领域 → 收集该领域高质量文档 → 喂入知识库 → 做好 Markdown 渲染和对话历史 → 找 20 个目标用户内测 → 根据反馈迭代\n\n这条路走通了，比做一个功能和 ChatGPT 一模一样但质量差一半的通用产品，更有商业价值。', '837ab7d6024abe1486ff93369dd595ce80d6aebf8fbeedc1bfc502f2787443fb', '{\"section\": \"五、最重要的一点\"}', 209, '2026-06-21 04:59:08');
INSERT INTO `kb_chunks` VALUES ('6f750101-260f-4bef-9257-f59d15eb432b:v1:0:cd514c153c860724', '6f750101-260f-4bef-9257-f59d15eb432b', '7693e1c2-c1dd-4e8f-b9a6-ebb112949c34', 10, 0, '?????X100??Wi-Fi7???????9.6Gbps?????2.5G?????????????????400-123-8899?', 'cd514c153c86072467db1d0d25679551e418713a8f8fd2a66ea169859e21d5ad', '{\"section\": \"???????\"}', 70, '2026-06-06 07:08:46');
INSERT INTO `kb_chunks` VALUES ('888d4ab5-1269-4e8a-b4d3-a3e6284ab963:v1:0:056278f67e73493a', '888d4ab5-1269-4e8a-b4d3-a3e6284ab963', '7693e1c2-c1dd-4e8f-b9a6-ebb112949c34', 10, 0, '星云路由器X100支持Wi-Fi7，最大无线速率9.6Gbps，提供四个2.5G网口。设备质保期为三年。售后热线是400-123-8899。', '056278f67e73493a80ab89b12e546db45312ef26c251120607e404ca9beaf95e', '{\"section\": \"星云路由器中文规格\"}', 70, '2026-06-06 07:09:28');
INSERT INTO `kb_chunks` VALUES ('bab47b79-5270-483b-826d-6aa66d32d010_chunk_0', 'bab47b79-5270-483b-826d-6aa66d32d010', 'e9788ee0-27b2-43ac-b6bb-3266db8f591b', 6, 0, 'FastAPI是一个现代、快速的Python Web框架，用于构建API。它基于Starlette和Pydantic，具有自动生成OpenAPI文档、类型检查和异步支持等特性。FastAPI的性能与Node.js和Go相当。', '37f6316991a85e374946ad55f95b7cf68e03b671c65056af91935952172d81da', '{}', 112, '2026-06-06 07:05:35');
INSERT INTO `kb_chunks` VALUES ('be6f7663-a6dc-494d-9307-8367c87c0df8:v1:0:25dd88dab6418b86', 'be6f7663-a6dc-494d-9307-8367c87c0df8', '2cb41af7-af7d-4b27-9404-bef621770b59', 2, 0, '# 11\n\n**5. 文件上传 + 分析（核心差异化）**\n\n用户上传 PDF、Word、Excel，AI 直接分析。这结合你已有的 RAG 体系，是最大亮点。\n\njava\n\n```java\n// 后端接收文件，动态写入向量库\n@PostMapping(\"/upload\")\npublic Result<?> uploadDocument(@RequestParam MultipartFile file,\n                                 @RequestParam String sessionId) {\n    // 解析文件 → 切片 → 向量化 → 存入用户专属的 Redis namespace\n}\n```\n\n**6. 知识库管理页面**\n\n让用户自己上传文档建立私有知识库，这是 ChatGPT 免费版没有的功能。\n\n```\n我的知识库\n├── 公司规章制度.pdf  ✓\n├── 产品手册v2.docx  ✓\n└── 竞品分析报告.xlsx ✓\n\n[+ 上传文档]\n```\n\n**7. 提示词模板市场**\n\n预设场景模板，降低用户使用门槛：\n\n```\n📝 合同审查    🔍 竞品分析\n📊 数据解读    💡 头脑风暴\n📧 邮件撰写    🐛 代码调试\n```\n\n**8. 对话分享**\n\n生成分享链接，让用户把好的对话分享给同事，这是增长的关键。\n\n------', '25dd88dab6418b86498875c43f980420981533dbbeb9c41db0fa5fa19356733d', '{\"section\": \"11\"}', 334, '2026-06-25 12:20:15');
INSERT INTO `kb_chunks` VALUES ('be6f7663-a6dc-494d-9307-8367c87c0df8:v1:1:c0b44c2f2408daaa', 'be6f7663-a6dc-494d-9307-8367c87c0df8', '2cb41af7-af7d-4b27-9404-bef621770b59', 2, 1, '### 第三阶段：商业化功能（4-6个月）\n\n**9. 积分/会员体系**\n\n```\n免费版：每天 20 次对话，不能上传文件\nPro版：无限对话 + 文件上传 + 私有知识库\n企业版：私有部署 + API 接入 + 多人协作\n```\n\n**10. 团队协作**\n\n共享知识库、共享对话、@同事，打企业内部工具市场。\n\n**11. API 开放**\n\n让开发者调用你的服务，收 Token 费用。\n\n------', 'c0b44c2f2408daaac7a82ecce11390d2402e1b7c7a2c95447ce93649836eeb47', '{\"section\": \"第三阶段：商业化功能（4-6个月）\"}', 157, '2026-06-25 12:20:15');
INSERT INTO `kb_chunks` VALUES ('be6f7663-a6dc-494d-9307-8367c87c0df8:v1:2:bf7b901397ceab21', 'be6f7663-a6dc-494d-9307-8367c87c0df8', '2cb41af7-af7d-4b27-9404-bef621770b59', 2, 2, '## 四、技术优化清单\n\n**后端优化**\n\n| 问题           | 当前状况             | 优化方案                                   |\n| -------------- | -------------------- | ------------------------------------------ |\n| 流式响应编码   | 可能有乱码           | 明确设置 `text/event-stream;charset=UTF-8` |\n| 没有限流       | 单用户可打爆服务     | 加 Redis 限流，每分钟最多 20 次            |\n| 向量库每次重建 | `store()` 方法被注释 | 启动时检查是否已有数据，有则跳过           |\n| 没有异常监控   | 出错只打日志         | 接入 Sentry 或钉钉/企微告警                |\n\n**前端优化**\n\n| 问题             | 优化方案                           |\n| ---------------- | ---------------------------------- |\n| 无 Markdown 渲染 | 引入 marked + highlight.js         |\n| 打字机效果卡顿   | 当前逐字符显示性能差，改为逐词显示 |\n| 无骨架屏         | 加载时显示骨架，减少白屏感知       |\n| 不支持移动端     | 响应式布局适配，或做 PWA           |\n\n------', 'bf7b901397ceab21a8dece29586bbada035a9eb5606485076f7ec786bfc42aa1', '{\"section\": \"四、技术优化清单\"}', 394, '2026-06-25 12:20:15');
