INSERT INTO `kb_chunks` VALUES ('d1e3fb7e-3229-4dc5-9015-e89b4fbe478e_chunk_0', 'd1e3fb7e-3229-4dc5-9015-e89b4fbe478e', 'e9788ee0-27b2-43ac-b6bb-3266db8f591b', 6, 0, '机器学习是人工智能的一个分支，使计算机能够从数据中学习和改进。主要分为监督学习、无监督学习和强化学习。常见的算法包括线性回归、决策树、支持向量机和神经网络。', '52816472023ba92ae23e09812f1a76ecfe0966df9fdcc69809b0184390bdc61f', '{}', 78, '2026-06-06 07:05:36');
