INSERT INTO `messages` VALUES (81, 20, 'assistant', '你好！我是 **DeepSeek**，一个由深度求索公司创造的AI助手。我是纯文本模型，可以帮你解答问题、处理文档、进行对话交流等。我支持上传图像、txt、pdf、ppt、word、excel文件并读取其中的文字信息，还支持联网搜索（需要你在Web或App端手动开启）。我的上下文长度可达1M，可以一次性处理像《三体》三部曲那样体量的书籍。而且我完全免费，知识截止日期到2025年5月。\n\n有什么我可以帮你的吗？😊', NULL, '2026-06-10 12:27:40', '[]');
