INSERT INTO `messages` VALUES (87, 20, 'assistant', '这个附件我已经读取了，内容是一条笔记：\n\n> 📖 **讲义链接**：`https://www.yuque.com/zhangzhijun-91vgw/javaai1.0?#`\n> 📌 **课程名称**：《Java+AI智能应用开发（线上训练营）v1.0》\n> 🔑 **密码**：`nxyt`\n\n不过需要注意，我**无法直接访问外部链接**（包括语雀文档），所以没办法帮你拉取讲义里的具体内容。如果你想让我帮你提取或分析这份讲义，可以这样操作：\n\n1. **复制粘贴**：打开语雀链接后，把需要分析的文字内容直接粘贴到对话框里。\n2. **导出上传**：把讲义导出为 PDF / Word / txt 等文件，然后上传给我。\n\n你可以根据需要选一种方式，我随时帮你处理！😊', NULL, '2026-06-10 12:32:16', '[]');
